import type { NextRequest } from 'next/server'

export function middleware(request: NextRequest) {
  const url = request.nextUrl.clone()
  const path = url.pathname
  const start = Date.now()

  // Skip static files, API routes, admin pages
  if (path.startsWith('/_next') || path.startsWith('/api') || path.startsWith('/admin') || 
      path === '/favicon.svg' || path.startsWith('/images')) {
    console.log(`[nexa-middleware] skip: ${path} ${Date.now() - start}ms`)
    return NextResponse.next()
  }

  // Log all content requests
  console.log(`[nexa-middleware] served: ${path} ${Date.now() - start}ms`)
  return NextResponse.next()
}

export const config = {
  matcher: [
    '/((?!_next|api|admin|favicon\\.svg|images).*)',
  ],
}
