import path from 'path'

export default function Home({ content, pageConfig }: any) {
  const siteName = content?.siteName || 'Nexa Paraguay'
  const sections = pageConfig?.sections || []

  return (
    <main style={{maxWidth:'1200px',margin:'0 auto',padding:'2rem 1rem'}}>
      <h1 style={{fontSize:'2rem',fontWeight:'bold',textAlign:'center',padding:'3rem 0'}}>{siteName}</h1>
      {sections.map((section: any, idx: number) => {
        const key = section.content || section.id || 's' + idx
        if (section.enabledWhen && !content?.[section.enabledWhen]) return null
        let sc = content?.[key]
        if (!sc && typeof key === 'string' && key.includes('.')) {
          sc = key.split('.').reduce((o: any, k: string) => o?.[k], content)
        }
        if (!sc && section.id) sc = content?.[section.id]
        if (!sc) return null
        if (typeof sc === 'string') {
          return <section key={key} style={{padding:'1rem',margin:'0.5rem 0',background:'#f4f4f4',borderRadius:'6px'}}>{sc}</section>
        }
        if (Array.isArray(sc)) {
          return (
            <section key={key} style={{padding:'1.5rem 0'}}>
              <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fill,minmax(300px,1fr))',gap:'1.25rem'}}>
                {sc.map((item: any, i: number) => (
                  <div key={i} style={{padding:'1.25rem',borderRadius:'8px',background:'#f8f9fa'}}>
                    {item.title && <h3 style={{fontSize:'1.15rem',fontWeight:600,marginBottom:'0.5rem'}}>{item.title}</h3>}
                    {item.description && <p style={{color:'#555',lineHeight:1.5}}>{item.description}</p>}
                    {item.price && <p style={{fontSize:'1.1rem',fontWeight:700,color:'#0a0',marginTop:'0.5rem'}}>{item.price}</p>}
                  </div>
                ))}
              </div>
            </section>
          )
        }
        return null
      })}
    </main>
  )
}

function loadJSON(dir: string, file: string) {
  try { return JSON.parse(readFileSync(path.join(dir, file), 'utf-8')) }
  catch { return null }
}

export function getServerSideProps() {
  const pagesDir = path.join(process.cwd(), 'nexa-pages')
  const contentDir = path.join(process.cwd(), 'content')
  try {
    const content = loadJSON(contentDir, 'es.json')
    const pageConfig = loadJSON(pagesDir, 'home.json')
    console.log('[nexa-pages] SSR: content=' + (!!content) + ' page=' + (!!pageConfig) + 
      ' cwd=' + process.cwd())
    return { props: { content, pageConfig, timestamp: Date.now() } }
  } catch (e: any) {
    console.log('[nexa-pages] SSR error:', e.message)
    return { props: { content: { siteName: 'Nexa Paraguay' }, pageConfig: null, error: e.message } }
  }
}
